class MathUtils {
  static PI = 3.14159265;

  static circleArea(radius) {
    return MathUtils.PI * radius * radius;
  }

  static factorial(n) {
    if (n <= 1) return 1;
    return n * MathUtils.factorial(n - 1);
  }

  static clamp(value, min, max) {
    return Math.min(Math.max(value, min), max);
  }
}

