exercises.solution:
function createVault(secret) {
  return {
    verify(guess) {
      return guess === secret ? 'Correct!' : 'Wrong!';
    },
    hint() {
      return `Starts with '${secret[0]}' and ends with '${secret[secret.length - 1]}'`;
    }
  };
}

const vault = createVault('closure');
console.log(vault.verify('wrong'));
console.log(vault.hint());
console.log(vault.verify('closure'));
console.log(vault.secret);

