class ScoreTracker {
  #scores = [];

  addScore(score) {
    this.#scores.push(score);
  }

  get average() {
    if (this.#scores.length === 0) return 0;
    const sum = this.#scores.reduce((a, b) => a + b, 0);
    return sum / this.#scores.length;
  }

  get topScore() {
    if (this.#scores.length === 0) return 0;
    return Math.max(...this.#scores);
  }

  get count() {
    return this.#scores.length;
  }
}

